      SUBROUTINE DFIG_Converters_AvgOut()

!---------------------------------------
! Standard includes
!---------------------------------------

      INCLUDE 'nd.h'
      INCLUDE 'emtconst.h'
      INCLUDE 'emtstor.h'
      INCLUDE 's0.h'
      INCLUDE 's1.h'
      INCLUDE 's2.h'
      INCLUDE 's4.h'
      INCLUDE 'branches.h'
      INCLUDE 'pscadv3.h'
      INCLUDE 'fnames.h'
      INCLUDE 'radiolinks.h'
      INCLUDE 'matlab.h'
      INCLUDE 'rtconfig.h'

!---------------------------------------
! Function/Subroutine Declarations
!---------------------------------------

      REAL    EMTDC_VVDC    ! 
      REAL    P3PH3         ! 
      REAL    Q3PH3         ! 
!     SUBR    DGTL_RMS3     ! '3 Phase Digital RMS Meter'
!     SUBR    FilterOut     ! 
      REAL    REALPOLE      ! Real Pole
!     SUBR    Grid_side_ControlsOut  ! 
!     SUBR    Rotor_side_ControlsOut  ! 
!     SUBR    Crowbar_protOut  ! 
!     SUBR    ChopperOut    ! 
!     SUBR    ConvBridge_AvgOut  ! 

!---------------------------------------
! Variable Declarations
!---------------------------------------


! Electrical Node Indices
      INTEGER  SABC(3), NT_1, NT_2, NT_4(3)
      INTEGER  NT_6(3)

! Control Signals
      REAL     V_GS(3), Q_GS, Ecap_fltrd, RT_7
      REAL     RT_8, RT_12, I_RS(3), V_RS(3)
      REAL     Iconv(3), Ecap, Vdc_crowbar_on
      REAL     Rcrow, Lcrow, RT_17, RT_18, DC_cap
      REAL     P_RS, Econv(3), VsRMSpu

! Internal Variables
      INTEGER  IVD1_1
      REAL     RVD1_1

! Indexing variables
      INTEGER ICALL_NO                            ! Module call num
      INTEGER ISTOL, ISTOI, ISTOF, ISTOC, IT_0    ! Storage Indices
      INTEGER IPGB                                ! Control/Monitoring
      INTEGER ISUBS, SS(3), IBRCH(3), INODE       ! SS/Node/Branch/Xfmr


!---------------------------------------
! Local Indices
!---------------------------------------

! Dsdyn <-> Dsout transfer index storage

      NTXFR = NTXFR + 1

      ISTOL = TXFR(NTXFR,1)
      ISTOI = TXFR(NTXFR,2)
      ISTOF = TXFR(NTXFR,3)
      ISTOC = TXFR(NTXFR,4)

! Increment and assign runtime configuration call indices

      ICALL_NO  = NCALL_NO
      NCALL_NO  = NCALL_NO + 1

! Increment global storage indices

      IPGB      = NPGB
      NPGB      = NPGB + 10
      NCX       = NCX + 0
      INODE     = NNODE + 2
      NNODE     = NNODE + 22
      NCSCS     = NCSCS + 0
      NCSCR     = NCSCR + 0

! Initialize Subsystem Mapping

      ISUBS = NSUBS + 0
      NSUBS = NSUBS + 3

      DO IT_0 = 1,3
         SS(IT_0) = SUBS(ISUBS + IT_0)
      END DO

! Initialize Branch Mapping.

      IBRCH(1)     = NBRCH(SS(1))
      NBRCH(SS(1)) = NBRCH(SS(1)) + 3

      IBRCH(2)     = NBRCH(SS(2))
      NBRCH(SS(2)) = NBRCH(SS(2)) + 9

      IBRCH(3)     = NBRCH(SS(3))
      NBRCH(SS(3)) = NBRCH(SS(3)) + 1
!---------------------------------------
! Transfers from storage arrays
!---------------------------------------

      Q_GS     = STOF(ISTOF + 53)
      Ecap_fltrd = STOF(ISTOF + 54)
      RT_7     = STOF(ISTOF + 80)
      RT_8     = STOF(ISTOF + 81)
      RT_12    = STOF(ISTOF + 85)
      Ecap     = STOF(ISTOF + 112)
      Vdc_crowbar_on = STOF(ISTOF + 116)
      Rcrow    = STOF(ISTOF + 117)
      Lcrow    = STOF(ISTOF + 118)
      RT_17    = STOF(ISTOF + 119)
      RT_18    = STOF(ISTOF + 120)
      DC_cap   = STOF(ISTOF + 125)
      P_RS     = STOF(ISTOF + 130)
      VsRMSpu  = STOF(ISTOF + 134)

! Array (1:3) quantities...
      DO IT_0 = 1,3
         V_GS(IT_0) = STOF(ISTOF + 46 + IT_0)
         I_RS(IT_0) = STOF(ISTOF + 93 + IT_0)
         V_RS(IT_0) = STOF(ISTOF + 96 + IT_0)
         Iconv(IT_0) = STOF(ISTOF + 108 + IT_0)
         Econv(IT_0) = STOF(ISTOF + 130 + IT_0)
      END DO


!---------------------------------------
! Electrical Node Lookup
!---------------------------------------

      NT_1  = NODE(INODE + 7)
      NT_2  = NODE(INODE + 8)

! Array (1:3) quantities...
      DO IT_0 = 1,3
         SABC(IT_0) = NODE(INODE + 3 + IT_0)
         NT_4(IT_0) = NODE(INODE + 11 + IT_0)
         NT_6(IT_0) = NODE(INODE + 17 + IT_0)
      END DO

!---------------------------------------
! Configuration of Models
!---------------------------------------

      IF ( TIMEZERO ) THEN
         FILENAME = 'DFIG_Converters_Avg.dta'
         CALL EMTDC_OPENFILE
         SECTION = 'DATADSO:'
         CALL EMTDC_GOTOSECTION
      ENDIF
!---------------------------------------
! Generated code from module definition
!---------------------------------------


! 410:[const] Real Constant 

      RT_8 = 1.0

! 420:[multimeter] Multimeter 
      IVD1_1 = NRTCF
      NRTCF  = NRTCF + 5
      V_GS(1) = EMTDC_VVDC(SS(2), SABC(1), 0)
      V_GS(2) = EMTDC_VVDC(SS(2), SABC(2), 0)
      V_GS(3) = EMTDC_VVDC(SS(2), SABC(3), 0)
      RVD1_1 = RTCF(IVD1_1) * P3PH3(SS(2), (IBRCH(2)+7), (IBRCH(2)+8), (&
     &IBRCH(2)+9),RTCF(IVD1_1+2),0)
      IF (UPDATE_AG) CALL PSCAD_AGRG2(ICALL_NO,847566030,RVD1_1,"Pd")
      RVD1_1 = RTCF(IVD1_1) * Q3PH3(SS(2), (IBRCH(2)+7), (IBRCH(2)+8), (&
     &IBRCH(2)+9),RTCF(IVD1_1+2),0)
      IF (UPDATE_AG) CALL PSCAD_AGRG2(ICALL_NO,847566030,RVD1_1,"Qd")
      Q_GS = RVD1_1
      CALL DGTL_RMS3(256,SS(2),SABC(1),SABC(2),SABC(3),RTCF(IVD1_1+3),1.&
     &0,0.0,RVD1_1)
      RVD1_1 = RTCF(IVD1_1+1)*RVD1_1
      IF (UPDATE_AG) CALL PSCAD_AGRG2(ICALL_NO,847566030,RVD1_1,"Vd")
      VsRMSpu = RVD1_1
      IF (FIRSTSTEP) THEN
        CALL PSCAD_AGI2(ICALL_NO,847566030,1,"hide1")
        CALL PSCAD_AGI2(ICALL_NO,847566030,1,"hide2")
      ENDIF

! 430:[const] Real Constant 'DC Capacitor [uF]'

      DC_cap = 7500.0

! 450:[voltmetergnd] Voltmeter (Line - Ground) 'Econv'
      Econv(1) = EMTDC_VVDC(SS(2), NT_6(1), 0)
      Econv(2) = EMTDC_VVDC(SS(2), NT_6(2), 0)
      Econv(3) = EMTDC_VVDC(SS(2), NT_6(3), 0)

! 460:[ammeter] Current Meter 'Iconv'
      Iconv(1) = ( CBR((IBRCH(2)+4), SS(2)))
      Iconv(2) = ( CBR((IBRCH(2)+5), SS(2)))
      Iconv(3) = ( CBR((IBRCH(2)+6), SS(2)))

! 470:[voltmeter] Voltmeter (Line - Line) 'Ecap'
      Ecap = EMTDC_VVDC(SS(3), NT_1, NT_2)

! 480:[emtconst] Commonly Used Constants (pi...) 
      RT_12 = TWO_PI

! 530:[multimeter] Multimeter 
      IVD1_1 = NRTCF
      NRTCF  = NRTCF + 5
      I_RS(1) = ( CBR((IBRCH(1)+1), SS(1)))
      I_RS(2) = ( CBR((IBRCH(1)+2), SS(1)))
      I_RS(3) = ( CBR((IBRCH(1)+3), SS(1)))
      V_RS(1) = EMTDC_VVDC(SS(1), NT_4(1), 0)
      V_RS(2) = EMTDC_VVDC(SS(1), NT_4(2), 0)
      V_RS(3) = EMTDC_VVDC(SS(1), NT_4(3), 0)
      RVD1_1 = RTCF(IVD1_1) * P3PH3(SS(1), (IBRCH(1)+1), (IBRCH(1)+2), (&
     &IBRCH(1)+3),RTCF(IVD1_1+2),0)
      IF (UPDATE_AG) CALL PSCAD_AGRG2(ICALL_NO,1634455167,RVD1_1,"Pd")
      P_RS = RVD1_1
      IF (FIRSTSTEP) THEN
        CALL PSCAD_AGI2(ICALL_NO,1634455167,1,"hide1")
        CALL PSCAD_AGI2(ICALL_NO,1634455167,1,"hide2")
      ENDIF

! 540:[Filter]  
      CALL FilterOut()


! 560:[const] Real Constant 'Chopper on voltage  [pu]'

      RT_18 = 1.15

! 590:[const] Real Constant 

      RT_7 = 2.0

! 610:[const] Real Constant 'Chopper Off voltage [pu]'

      RT_17 = 1.11

! 650:[realpole] Real Pole 
!  Real_Pole
      Ecap_fltrd = REALPOLE(0,1,0,1.0,0.005,Ecap,0.0,-10.0,10.0)

! 680:[const] Real Constant 'DC crowbar on voltage [kV]'

      Vdc_crowbar_on = 1.75

! 690:[const] Real Constant 'Crowbar Resistance [ohm]'

      Rcrow = 0.001

! 700:[const] Real Constant 'Crowbar Inductance [H]'

      Lcrow = 0.04

! 710:[pgb] Output Channel 'Ecap_Det'

      PGB(IPGB+1) = Ecap

! 720:[pgb] Output Channel 'I_RS'

      DO IVD1_1 = 1, 3
         PGB(IPGB+2+IVD1_1-1) = I_RS(IVD1_1)
      ENDDO

! 730:[pgb] Output Channel 'V_RS'

      DO IVD1_1 = 1, 3
         PGB(IPGB+5+IVD1_1-1) = V_RS(IVD1_1)
      ENDDO

! 740:[pgb] Output Channel 'Iconv'

      DO IVD1_1 = 1, 3
         PGB(IPGB+8+IVD1_1-1) = Iconv(IVD1_1)
      ENDDO

! 750:[Grid_side_Controls]  
      CALL Grid_side_ControlsOut()


! 870:[Rotor_side_Controls]  
      CALL Rotor_side_ControlsOut()


! 950:[Crowbar_prot]  
      CALL Crowbar_protOut()


! 970:[Chopper]  
      CALL ChopperOut()


! 980:[ConvBridge_Avg]  
      CALL ConvBridge_AvgOut()


! 1000:[ConvBridge_Avg]  
      CALL ConvBridge_AvgOut()


!---------------------------------------
! Feedbacks and transfers to storage
!---------------------------------------

      STOF(ISTOF + 53) = Q_GS
      STOF(ISTOF + 54) = Ecap_fltrd
      STOF(ISTOF + 80) = RT_7
      STOF(ISTOF + 81) = RT_8
      STOF(ISTOF + 85) = RT_12
      STOF(ISTOF + 112) = Ecap
      STOF(ISTOF + 116) = Vdc_crowbar_on
      STOF(ISTOF + 117) = Rcrow
      STOF(ISTOF + 118) = Lcrow
      STOF(ISTOF + 119) = RT_17
      STOF(ISTOF + 120) = RT_18
      STOF(ISTOF + 125) = DC_cap
      STOF(ISTOF + 130) = P_RS
      STOF(ISTOF + 134) = VsRMSpu

! Array (1:3) quantities...
      DO IT_0 = 1,3
         STOF(ISTOF + 46 + IT_0) = V_GS(IT_0)
         STOF(ISTOF + 93 + IT_0) = I_RS(IT_0)
         STOF(ISTOF + 96 + IT_0) = V_RS(IT_0)
         STOF(ISTOF + 108 + IT_0) = Iconv(IT_0)
         STOF(ISTOF + 130 + IT_0) = Econv(IT_0)
      END DO


!---------------------------------------
! Close Model Data read
!---------------------------------------

      IF ( TIMEZERO ) CALL EMTDC_CLOSEFILE
      RETURN
      END

