      SUBROUTINE DFIG_Converters_AvgDyn_Begin(Pbase, Mrating,           &
     &   Filter_Calc, freq_cutoff, freq, Vhv, Cfilter_in, Cdamp_in,     &
     &   Ldamp_in, Rdamp_in, M_kv, Rst_pu, Slip_max, TRN, Vac_Gsc,      &
     &   Vdc_base, Lconv_Gsc, Cfreq_Gsc, Vac_Rsc, Cfreq_Rsc)

!---------------------------------------
! Standard includes
!---------------------------------------

      INCLUDE 'nd.h'
      INCLUDE 'emtconst.h'
      INCLUDE 's0.h'
      INCLUDE 's1.h'
      INCLUDE 's4.h'
      INCLUDE 'branches.h'
      INCLUDE 'pscadv3.h'
      INCLUDE 'radiolinks.h'
      INCLUDE 'rtconfig.h'

!---------------------------------------
! Function/Subroutine Declarations
!---------------------------------------

!     SUBR    FilterDyn_Begin  ! 
!     SUBR    Grid_side_ControlsDyn_Begin  ! 
!     SUBR    Rotor_side_ControlsDyn_Begin  ! 
!     SUBR    Crowbar_protDyn_Begin  ! 
!     SUBR    ChopperDyn_Begin  ! 
!     SUBR    ConvBridge_AvgDyn_Begin  ! 

!---------------------------------------
! Variable Declarations
!---------------------------------------


! Subroutine Arguments
      INTEGER, INTENT(IN)  :: Filter_Calc
      REAL,    INTENT(IN)  :: Pbase, Mrating
      REAL,    INTENT(IN)  :: freq_cutoff, freq
      REAL,    INTENT(IN)  :: Vhv, Cfilter_in
      REAL,    INTENT(IN)  :: Cdamp_in, Ldamp_in
      REAL,    INTENT(IN)  :: Rdamp_in, M_kv
      REAL,    INTENT(IN)  :: Rst_pu, Slip_max
      REAL,    INTENT(IN)  :: TRN, Vac_Gsc
      REAL,    INTENT(IN)  :: Vdc_base, Lconv_Gsc
      REAL,    INTENT(IN)  :: Cfreq_Gsc, Vac_Rsc
      REAL,    INTENT(IN)  :: Cfreq_Rsc

! Electrical Node Indices

! Control Signals
      REAL     RT_7, RT_8, RT_12, Vdc_crowbar_on
      REAL     Rcrow, Lcrow, RT_17, RT_18, DC_cap

! Internal Variables
      INTEGER  IVD1_1, IVD1_2, IVD1_3
      REAL     RVD1_1, RVD1_2, RVD1_3

! Indexing variables
      INTEGER ICALL_NO                            ! Module call num
      INTEGER IT_0                                ! Storage Indices
      INTEGER ICX                                 ! Control/Monitoring
      INTEGER ISUBS, SS(3), IBRCH(3), INODE       ! SS/Node/Branch/Xfmr


!---------------------------------------
! Local Indices
!---------------------------------------


! Increment and assign runtime configuration call indices

      ICALL_NO  = NCALL_NO
      NCALL_NO  = NCALL_NO + 1

! Increment global storage indices

      ICX       = NCX
      NCX       = NCX + 3
      INODE     = NNODE + 2
      NNODE     = NNODE + 22
      NCSCS     = NCSCS + 0
      NCSCR     = NCSCR + 0

! Initialize Subsystem Mapping

      ISUBS = NSUBS + 0
      NSUBS = NSUBS + 3

      DO IT_0 = 1,3
         SS(IT_0) = SUBS(ISUBS + IT_0)
      END DO

! Initialize Branch Mapping.

      IBRCH(1)     = NBRCH(SS(1))
      NBRCH(SS(1)) = NBRCH(SS(1)) + 3

      IBRCH(2)     = NBRCH(SS(2))
      NBRCH(SS(2)) = NBRCH(SS(2)) + 9

      IBRCH(3)     = NBRCH(SS(3))
      NBRCH(SS(3)) = NBRCH(SS(3)) + 1
!---------------------------------------
! Electrical Node Lookup
!---------------------------------------


!---------------------------------------
! Generated code from module definition
!---------------------------------------


! 30:[datatap] Scalar/Array Tap 

! 110:[datatap] Scalar/Array Tap 

! 130:[unity] Type conversion block 

! 180:[datatap] Scalar/Array Tap 

! 200:[unity] Type conversion block 

! 240:[datatap] Scalar/Array Tap 

! 300:[datatap] Scalar/Array Tap 

! 330:[datatap] Scalar/Array Tap 

! 380:[datatap] Scalar/Array Tap 

! 390:[unity] Type conversion block 

! 400:[inv] Interpolated Logic Inverter 

! 410:[const] Real Constant 
      RT_8 = 1.0

! 430:[const] Real Constant 'DC Capacitor [uF]'
      DC_cap = 7500.0

! 440:[rtcbranch] Runtime Configurable Passive Branch 
      IVD1_1 = 0
      RVD1_1 = 0.0
      CALL CHECK_INEQUILITY(3,Lconv_Gsc,0.0,IVD1_2)
      RVD1_2 = Lconv_Gsc
      IVD1_3 = 0
      RVD1_3 = 0.0
      CALL E_BRANCH_CFG( (IBRCH(2)+1),SS(2),IVD1_1,IVD1_2,IVD1_3,RVD1_1,&
     &RVD1_2,RVD1_3)
      CALL E_BRANCH_CFG( (IBRCH(2)+2),SS(2),IVD1_1,IVD1_2,IVD1_3,RVD1_1,&
     &RVD1_2,RVD1_3)
      CALL E_BRANCH_CFG( (IBRCH(2)+3),SS(2),IVD1_1,IVD1_2,IVD1_3,RVD1_1,&
     &RVD1_2,RVD1_3)

! 480:[emtconst] Commonly Used Constants (pi...) 
      RT_12 = TWO_PI

! 490:[varrlc] Variable R, L or C  
      CALL E_VARRLC1_CFG(2 ,SS(3) ,  (IBRCH(3)+1), 0)

! 500:[mult] Multiplier 

! 510:[square] Square 

! 520:[mult] Multiplier 

! 540:[Filter]  
      CALL FilterDyn_Begin(Ldamp_in, Cfilter_in, Cdamp_in, Rdamp_in, Lco&
     &nv_Gsc)


! 550:[gain] Gain Block 

! 560:[const] Real Constant 'Chopper on voltage  [pu]'
      RT_18 = 1.15

! 570:[var] Variable Input Slider 'Time_crowbar'

! 580:[mult] Multiplier 

! 590:[const] Real Constant 
      RT_7 = 2.0

! 600:[var] Variable Input Slider 'Maximum rotor Current'

! 610:[const] Real Constant 'Chopper Off voltage [pu]'
      RT_17 = 1.11

! 620:[div] Divider 

! 630:[mult] Multiplier 

! 640:[div] Divider 

! 660:[inv] Interpolated Logic Inverter 

! 670:[var_switch] Two State Switch 'Crow bar enable (1), disable (0)'

! 680:[const] Real Constant 'DC crowbar on voltage [kV]'
      Vdc_crowbar_on = 1.75

! 690:[const] Real Constant 'Crowbar Resistance [ohm]'
      Rcrow = 0.001

! 700:[const] Real Constant 'Crowbar Inductance [H]'
      Lcrow = 0.04

! 750:[Grid_side_Controls]  
      CALL Grid_side_ControlsDyn_Begin(Vac_Gsc, freq, freq_cutoff, Vdc_b&
     &ase, Lconv_Gsc)


! 760:[datatap] Scalar/Array Tap 

! 770:[datatap] Scalar/Array Tap 

! 780:[datatap] Scalar/Array Tap 

! 790:[datamerge] Merges data signals into an array 

! 810:[div] Divider 

! 820:[gain] Gain Block 

! 830:[div] Divider 

! 840:[div] Divider 

! 850:[sqrt] Square Root 

! 860:[gain] Gain Block 

! 870:[Rotor_side_Controls]  
      CALL Rotor_side_ControlsDyn_Begin(freq, Rst_pu, 0.8, 0.0, 0.9, 1.1&
     &, 0.02, M_kv, Slip_max, TRN)


! 880:[datatap] Scalar/Array Tap 

! 890:[datatap] Scalar/Array Tap 

! 900:[datatap] Scalar/Array Tap 

! 910:[unity] Type conversion block 

! 920:[datamerge] Merges data signals into an array 

! 930:[select] Two Input Selector 
      RTCI(NRTCI) = 0
      NRTCI = NRTCI + 1

! 940:[select] Two Input Selector 
      RTCI(NRTCI) = 0
      NRTCI = NRTCI + 1

! 950:[Crowbar_prot]  
      CALL Crowbar_protDyn_Begin(Rcrow, Lcrow)


! 960:[select] Two Input Selector 
      RTCI(NRTCI) = 0
      NRTCI = NRTCI + 1

! 970:[Chopper]  
      CALL ChopperDyn_Begin()


! 980:[ConvBridge_Avg]  
      CALL ConvBridge_AvgDyn_Begin(0.0005)


! 990:[select] Two Input Selector 
      RTCI(NRTCI) = 0
      NRTCI = NRTCI + 1

! 1000:[ConvBridge_Avg]  
      CALL ConvBridge_AvgDyn_Begin(0.0005)


! 1010:[zminusone] Feedback Loop Selector 'Unused'

      RETURN
      END

