      SUBROUTINE DFIG_Converters_AvgOut_Begin(Pbase, Mrating,           &
     &   Filter_Calc, freq_cutoff, freq, Vhv, Cfilter_in, Cdamp_in,     &
     &   Ldamp_in, Rdamp_in, M_kv, Rst_pu, Slip_max, TRN, Vac_Gsc,      &
     &   Vdc_base, Lconv_Gsc, Cfreq_Gsc, Vac_Rsc, Cfreq_Rsc)

!---------------------------------------
! Standard includes
!---------------------------------------

      INCLUDE 'nd.h'
      INCLUDE 'emtconst.h'
      INCLUDE 's0.h'
      INCLUDE 's1.h'
      INCLUDE 's4.h'
      INCLUDE 'branches.h'
      INCLUDE 'pscadv3.h'
      INCLUDE 'radiolinks.h'
      INCLUDE 'rtconfig.h'

!---------------------------------------
! Function/Subroutine Declarations
!---------------------------------------

!     SUBR    FilterOut_Begin  ! 
!     SUBR    Grid_side_ControlsOut_Begin  ! 
!     SUBR    Rotor_side_ControlsOut_Begin  ! 
!     SUBR    Crowbar_protOut_Begin  ! 
!     SUBR    ChopperOut_Begin  ! 
!     SUBR    ConvBridge_AvgOut_Begin  ! 

!---------------------------------------
! Variable Declarations
!---------------------------------------


! Subroutine Arguments
      INTEGER, INTENT(IN)  :: Filter_Calc
      REAL,    INTENT(IN)  :: Pbase, Mrating
      REAL,    INTENT(IN)  :: freq_cutoff, freq
      REAL,    INTENT(IN)  :: Vhv, Cfilter_in
      REAL,    INTENT(IN)  :: Cdamp_in, Ldamp_in
      REAL,    INTENT(IN)  :: Rdamp_in, M_kv
      REAL,    INTENT(IN)  :: Rst_pu, Slip_max
      REAL,    INTENT(IN)  :: TRN, Vac_Gsc
      REAL,    INTENT(IN)  :: Vdc_base, Lconv_Gsc
      REAL,    INTENT(IN)  :: Cfreq_Gsc, Vac_Rsc
      REAL,    INTENT(IN)  :: Cfreq_Rsc

! Electrical Node Indices
      INTEGER  SABC(3), NT_1, NT_2, NT_4(3)
      INTEGER  NT_6(3)

! Control Signals
      REAL     RT_7, RT_8, RT_12, Vdc_crowbar_on
      REAL     Rcrow, Lcrow, RT_17, RT_18, DC_cap

! Internal Variables
      INTEGER  IVD1_1

! Indexing variables
      INTEGER ICALL_NO                            ! Module call num
      INTEGER IT_0                                ! Storage Indices
      INTEGER ISUBS, SS(3), IBRCH(3), INODE       ! SS/Node/Branch/Xfmr


!---------------------------------------
! Local Indices
!---------------------------------------


! Increment and assign runtime configuration call indices

      ICALL_NO  = NCALL_NO
      NCALL_NO  = NCALL_NO + 1

! Increment global storage indices

      NCX       = NCX + 0
      INODE     = NNODE + 2
      NNODE     = NNODE + 22
      NCSCS     = NCSCS + 0
      NCSCR     = NCSCR + 0

! Initialize Subsystem Mapping

      ISUBS = NSUBS + 0
      NSUBS = NSUBS + 3

      DO IT_0 = 1,3
         SS(IT_0) = SUBS(ISUBS + IT_0)
      END DO

! Initialize Branch Mapping.

      IBRCH(1)     = NBRCH(SS(1))
      NBRCH(SS(1)) = NBRCH(SS(1)) + 3

      IBRCH(2)     = NBRCH(SS(2))
      NBRCH(SS(2)) = NBRCH(SS(2)) + 9

      IBRCH(3)     = NBRCH(SS(3))
      NBRCH(SS(3)) = NBRCH(SS(3)) + 1
!---------------------------------------
! Electrical Node Lookup
!---------------------------------------

      NT_1  = NODE(INODE + 7)
      NT_2  = NODE(INODE + 8)

! Array (1:3) quantities...
      DO IT_0 = 1,3
         SABC(IT_0) = NODE(INODE + 3 + IT_0)
         NT_4(IT_0) = NODE(INODE + 11 + IT_0)
         NT_6(IT_0) = NODE(INODE + 17 + IT_0)
      END DO

!---------------------------------------
! Generated code from module definition
!---------------------------------------


! 410:[const] Real Constant 
      RT_8 = 1.0

! 420:[multimeter] Multimeter 
      IVD1_1 = NRTCF
      NRTCF  = NRTCF + 5
      IF (ABS(1.0) .GT. 1.0E-20) THEN
        RTCF(IVD1_1) = 1.0/ABS(1.0)
      ELSE
        RTCF(IVD1_1) = 1.0
      ENDIF
      IF (ABS(1.0) .GT. 1.0E-20) THEN
        RTCF(IVD1_1+1) = 1.0/ABS(1.0)
      ELSE
        RTCF(IVD1_1+1) = 1.0
      ENDIF
      RTCF(IVD1_1+2) = 0.02
      RTCF(IVD1_1+3) = freq

! 430:[const] Real Constant 'DC Capacitor [uF]'
      DC_cap = 7500.0

! 480:[emtconst] Commonly Used Constants (pi...) 
      RT_12 = TWO_PI

! 530:[multimeter] Multimeter 
      IVD1_1 = NRTCF
      NRTCF  = NRTCF + 5
      IF (ABS(1.0) .GT. 1.0E-20) THEN
        RTCF(IVD1_1) = 1.0/ABS(1.0)
      ELSE
        RTCF(IVD1_1) = 1.0
      ENDIF
      RTCF(IVD1_1+2) = 0.02

! 540:[Filter]  
      CALL FilterOut_Begin(Ldamp_in, Cfilter_in, Cdamp_in, Rdamp_in, Lco&
     &nv_Gsc)


! 560:[const] Real Constant 'Chopper on voltage  [pu]'
      RT_18 = 1.15

! 590:[const] Real Constant 
      RT_7 = 2.0

! 610:[const] Real Constant 'Chopper Off voltage [pu]'
      RT_17 = 1.11

! 650:[realpole] Real Pole 

! 680:[const] Real Constant 'DC crowbar on voltage [kV]'
      Vdc_crowbar_on = 1.75

! 690:[const] Real Constant 'Crowbar Resistance [ohm]'
      Rcrow = 0.001

! 700:[const] Real Constant 'Crowbar Inductance [H]'
      Lcrow = 0.04

! 710:[pgb] Output Channel 'Ecap_Det'

! 720:[pgb] Output Channel 'I_RS'

! 730:[pgb] Output Channel 'V_RS'

! 740:[pgb] Output Channel 'Iconv'

! 750:[Grid_side_Controls]  
      CALL Grid_side_ControlsOut_Begin(Vac_Gsc, freq, freq_cutoff, Vdc_b&
     &ase, Lconv_Gsc)


! 870:[Rotor_side_Controls]  
      CALL Rotor_side_ControlsOut_Begin(freq, Rst_pu, 0.8, 0.0, 0.9, 1.1&
     &, 0.02, M_kv, Slip_max, TRN)


! 950:[Crowbar_prot]  
      CALL Crowbar_protOut_Begin(Rcrow, Lcrow)


! 970:[Chopper]  
      CALL ChopperOut_Begin()


! 980:[ConvBridge_Avg]  
      CALL ConvBridge_AvgOut_Begin(0.0005)


! 1000:[ConvBridge_Avg]  
      CALL ConvBridge_AvgOut_Begin(0.0005)


      RETURN
      END

